def most_common_word(s):
    if not s:
        return ''

    word_count = {}
    words = s.lower().split()

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    max_count = max(word_count.values())
    result = [word for word, count in word_count.items() if count == max_count]

    return min(sorted(result))
